def main() -> None:
    initialize()
    process_data()
    finalize()

def initialize() -> None:
    print("Program initialized.")

def process_data() -> None:
    data = [1, 2, 3, 4, 5]
    total = 0
    for value in data:
        total += value
    print("Total:", total)

def finalize() -> None:
    print("Program finalized.")

if __name__ == "__main__":
    main()
